class MyQueue {
  constructor() { this.inStack = []; this.outStack = []; }
  push(x) { this.inStack.push(x); }
  pop() { this._transfer(); return this.outStack.pop(); }
  peek() { this._transfer(); return this.outStack[this.outStack.length - 1]; }
  empty() { return !this.inStack.length && !this.outStack.length; }
  _transfer() {
    if (!this.outStack.length)
      while (this.inStack.length) this.outStack.push(this.inStack.pop());
  }
}

function longestCommonSubsequence(text1, text2) {
  const m = text1.length, n = text2.length;
  const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
  for (let i = 1; i <= m; i++)
    for (let j = 1; j <= n; j++)
      dp[i][j] = text1[i-1] === text2[j-1]
        ? dp[i-1][j-1] + 1
        : Math.max(dp[i-1][j], dp[i][j-1]);
  return dp[m][n];
}

function knapsack(weights, values, capacity) {
  const n = weights.length;
  const dp = Array.from({ length: n + 1 }, () => new Array(capacity + 1).fill(0));
  for (let i = 1; i <= n; i++)
    for (let w = 0; w <= capacity; w++)
      dp[i][w] = weights[i-1] <= w
        ? Math.max(dp[i-1][w], dp[i-1][w - weights[i-1]] + values[i-1])
        : dp[i-1][w];
  return dp[n][capacity];
}

function findKthLargest(nums, k) {
  // Using quickselect (average O(n))
  function partition(lo, hi) {
    const pivot = nums[hi];
    let i = lo;
    for (let j = lo; j < hi; j++)
      if (nums[j] >= pivot) [nums[i], nums[j]] = [nums[j], nums[i]], i++;
    [nums[i], nums[hi]] = [nums[hi], nums[i]];
    return i;
  }
  let lo = 0, hi = nums.length - 1;
  while (true) {
    const p = partition(lo, hi);
    if (p === k - 1) return nums[p];
    if (p < k - 1) lo = p + 1;
    else hi = p - 1;
  }
}

